# scripts/check_schema_compat.py
"""
Check whether a new schema is backward-compatible with an old schema.
Backward-compatible means: all existing callers continue to work.
Usage: python check_schema_compat.py contracts/tools/search.schema.json new.schema.json
"""
import sys
import json
from pathlib import Path
from dataclasses import dataclass, field

@dataclass
class CompatReport:
    breaking: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)
    safe: list[str] = field(default_factory=list)

    @property
    def is_compatible(self) -> bool:
        return len(self.breaking) == 0

def get_required(schema: dict) -> set[str]:
    return set(schema.get("required", []))

def get_properties(schema: dict) -> dict:
    return schema.get("properties", {})

def get_enum(prop: dict) -> set | None:
    if "enum" in prop:
        return set(prop["enum"])
    if "allOf" in prop:
        for sub in prop["allOf"]:
            if "enum" in sub:
                return set(sub["enum"])
    return None

def check_compat(old: dict, new: dict) -> CompatReport:
    report = CompatReport()
    old_props = get_properties(old)
    new_props = get_properties(new)
    old_required = get_required(old)
    new_required = get_required(new)

    # Removed required fields
    for field_name in old_required - new_required:
        if field_name not in new_props:
            report.breaking.append(f"Required field '{field_name}' was removed")
        else:
            report.safe.append(f"Field '{field_name}' downgraded from required to optional (safe)")

    # Added required fields
    for field_name in new_required - old_required:
        report.breaking.append(f"New required field '{field_name}' added — existing callers won't supply it")

    # Type changes in existing fields
    for field_name, old_prop in old_props.items():
        if field_name not in new_props:
            if field_name in old_required:
                pass  # already caught above
            else:
                report.warnings.append(f"Optional field '{field_name}' removed — callers using it will break")
            continue
        new_prop = new_props[field_name]
        if old_prop.get("type") != new_prop.get("type"):
            report.breaking.append(
                f"Field '{field_name}' type changed: {old_prop.get('type')} → {new_prop.get('type')}"
            )
        # Enum: removed values are breaking
        old_enum = get_enum(old_prop)
        new_enum = get_enum(new_prop)
        if old_enum and new_enum:
            removed = old_enum - new_enum
            added = new_enum - old_enum
            for v in removed:
                report.breaking.append(f"Field '{field_name}' enum value '{v}' removed")
            for v in added:
                report.warnings.append(f"Field '{field_name}' enum value '{v}' added — handlers must handle it")

    # New optional fields
    for field_name in new_props:
        if field_name not in old_props and field_name not in new_required:
            report.safe.append(f"New optional field '{field_name}' added")

    return report

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: check_schema_compat.py <old.schema.json> <new.schema.json>")
        sys.exit(1)
    old = json.loads(Path(sys.argv[1]).read_text())
    new = json.loads(Path(sys.argv[2]).read_text())
    report = check_compat(old, new)
    for msg in report.breaking:
        print(f"BREAKING: {msg}")
    for msg in report.warnings:
        print(f"WARNING:  {msg}")
    for msg in report.safe:
        print(f"SAFE:     {msg}")
    if not report.is_compatible:
        print("\nResult: BREAKING CHANGES — deployment blocked")
        sys.exit(1)
    print("\nResult: backward-compatible")

# tests/test_schema_contracts.py
import json
import pytest
from pathlib import Path
from tools.schemas import SearchToolInput, DatabaseQueryInput
from scripts.check_schema_compat import check_compat

CONTRACTS_DIR = Path("contracts/tools")

class TestSchemaStability:
    """Verify live models match committed contract files."""

    def _assert_schema_matches_contract(self, model_cls, contract_name: str):
        contract_path = CONTRACTS_DIR / f"{contract_name}.schema.json"
        if not contract_path.exists():
            pytest.skip(f"No contract file at {contract_path} — run export_tool_schemas.py first")
        committed = json.loads(contract_path.read_text())
        live = model_cls.model_json_schema()
        live.pop("title", None)
        report = check_compat(committed, live)
        assert report.is_compatible, (
            f"Tool schema '{contract_name}' has breaking changes:\n"
            + "\n".join(report.breaking)
        )

    def test_search_schema_stable(self):
        self._assert_schema_matches_contract(SearchToolInput, "search")

    def test_database_query_schema_stable(self):
        self._assert_schema_matches_contract(DatabaseQueryInput, "query_database")

class TestCompatibilityChecker:
    """Unit tests for the breaking-change detector itself."""

    BASE = {
        "type": "object",
        "properties": {
            "query": {"type": "string"},
            "scope": {"type": "string", "enum": ["web", "news"]},
            "limit": {"type": "integer"},
        },
        "required": ["query"],
    }

    def test_additive_optional_field_is_safe(self):
        new = {**self.BASE, "properties": {**self.BASE["properties"], "lang": {"type": "string"}}}
        report = check_compat(self.BASE, new)
        assert report.is_compatible

    def test_adding_required_field_is_breaking(self):
        new = {**self.BASE, "required": ["query", "scope"]}
        report = check_compat(self.BASE, new)
        assert not report.is_compatible
        assert any("scope" in m for m in report.breaking)

    def test_removing_required_field_is_breaking(self):
        new = {**self.BASE, "required": [], "properties": {k: v for k, v in self.BASE["properties"].items() if k != "query"}}
        report = check_compat(self.BASE, new)
        assert not report.is_compatible

    def test_type_change_is_breaking(self):
        new_props = {**self.BASE["properties"], "limit": {"type": "string"}}
        new = {**self.BASE, "properties": new_props}
        report = check_compat(self.BASE, new)
        assert not report.is_compatible
        assert any("limit" in m for m in report.breaking)

    def test_removing_enum_value_is_breaking(self):
        new_props = {**self.BASE["properties"], "scope": {"type": "string", "enum": ["web"]}}
        new = {**self.BASE, "properties": new_props}
        report = check_compat(self.BASE, new)
        assert not report.is_compatible
        assert any("news" in m for m in report.breaking)
